 #[must_use]
 pub fn format_grpc_timeout(duration: Duration) -> String {
+    const MAX_VALUE: u128 = 99_999_999;
+    let ns = duration.as_nanos();
+    if ns == 0 {
+        return "0n".to_string();
+    }
+    let us = duration.as_micros();
+    if us <= MAX_VALUE {
