+    if ms <= MAX_VALUE {
+        return format!("{ms}m");
+    }
+    let secs = u128::from(duration.as_secs());
+    if secs <= MAX_VALUE {
+        return format!("{secs}S");
+    }
+    let mins = secs / 60;
+    if mins <= MAX_VALUE {
+        return format!("{mins}M");
+    }
+    let hours = mins / 60;
+    let hours = hours.min(MAX_VALUE);
+    format!("{hours}H")
 }

